// Robustly read the AI output (could be a JSON string, a parsed object,
// or wrapped under common keys) and expose flat fields for downstream nodes.
const ai = $json;
const form = $('Receive Form Submission').item.json.body || {};

function extractRaw(obj) {
  if (obj == null) return '';
  if (typeof obj === 'string') return obj;
  // Common shapes returned by the OpenAI node depending on options
  return (
    obj.content ??
    obj.message?.content ??
    obj.text ??
    obj.output_text ??
    obj.response ??
    obj
  );
}

function coerce(value) {
  if (value && typeof value === 'object') return value;
  if (typeof value !== 'string') return {};
  let s = value.trim();
  // Strip ```json ... ``` fences if the model added them anyway
  s = s.replace(/^```(?:json)?/i, '').replace(/```$/i, '').trim();
  try {
    return JSON.parse(s);
  } catch (e) {
    // Fall back to the first {...} block we can find
    const match = s.match(/\{[\s\S]*\}/);
    if (match) {
      try { return JSON.parse(match[0]); } catch (_) { /* noop */ }
    }
    return {};
  }
}

const parsed = coerce(extractRaw(ai));

const allowed = {
  category: ['sales', 'support', 'spam', 'other'],
  urgency: ['low', 'medium', 'high'],
  sentiment: ['positive', 'neutral', 'negative'],
};
function pick(field, fallback) {
  const v = String(parsed[field] ?? '').toLowerCase().trim();
  return allowed[field].includes(v) ? v : fallback;
}

return {
  json: {
    timestamp: new Date().toISOString(),
    name: form.name ?? '',
    email: form.email ?? '',
    message: form.message ?? '',
    category: pick('category', 'other'),
    urgency: pick('urgency', 'medium'),
    sentiment: pick('sentiment', 'neutral'),
    summary: String(parsed.summary ?? '').trim(),
    suggested_reply: String(parsed.suggested_reply ?? '').trim(),
  },
};
